class Solution {
public:
    vector<int> maxScoreIndices(vector<int>& nums) {
        int n = nums.size();
        vector<int> left(n, 0), right(n, 0);
        for (int i = 0; i < n; i++) {
            if (nums[i] == 0) left[i]++;
            else right[n - i - 1]++;
        }
        int max_score = left[0] + right[n - 1];
        vector<int> ans;
        for (int i = 0; i < n; i++) {
            if (left[i] + right[n - i - 1] == max_score) ans.push_back(i);
        }
        return ans;
    }
};
```

